"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[44514],{85558(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>o,default:()=>l,frontMatter:()=>s,metadata:()=>i,toc:()=>h});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets/player-transfer-payments-ias-38-7cb77accfb","title":"Player Transfer Payments (IAS 38)","description":"June 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets/Player Transfer Payments (IAS 38).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/player-transfer-payments-ias-38-7cb77accfb","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/player-transfer-payments-ias-38-7cb77accfb","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"player-transfer-payments-ias-38-7cb77accfb","title":"Player Transfer Payments (IAS 38)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/player-transfer-payments-ias-38-7cb77accfb","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/customer-s-right-to-receive-access-t-164bbd17bd"},"next":{"title":"Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/configuration-or-customisation-costs-acd1e0b2c4"}}');var a=n(74848),r=n(28453);let s={id:"player-transfer-payments-ias-38-7cb77accfb",title:"Player Transfer Payments (IAS 38)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/player-transfer-payments-ias-38-7cb77accfb",sidebar_position:2},o="Player Transfer Payments (IAS 38)",c={},h=[{value:"Recognition of transfer payment received",id:"recognition-of-transfer-payment-received",level:2},{value:"Does the transfer payment represent disposal proceeds?",id:"does-the-transfer-payment-represent-disposal-proceeds",level:2},{value:"Statement of cash flows",id:"statement-of-cash-flows",level:2}];function d(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"player-transfer-payments-ias-38",children:"Player Transfer Payments (IAS 38)"})}),"\n",(0,a.jsx)(t.p,{children:"June 2020"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about the recognition of player transfer payments received. In the fact pattern described in the request:"}),"\n",(0,a.jsx)(t.p,{children:"a. a football club (entity) transfers a player to another club (receiving club). When the entity recruited the player, the entity registered the player in an electronic transfer system. Registration means the player is prohibited from playing for another club, and requires the registering club to have an employment contract with the player that prevents the player from leaving the club without mutual agreement. Together the employment contract and registration in the electronic transfer system are referred to as a \u2018registration right\u2019.\nb. the entity had recognised costs incurred to obtain the registration right as an intangible asset applying IAS 38. As part of its ordinary activities, the entity uses and develops the player through participation in matches, and then potentially transfers the player to another club.\nc. the entity and the receiving club enter into a transfer agreement under which the entity receives a transfer payment from the receiving club. The transfer payment compensates the entity for releasing the player from the employment contract before the contract ends. The registration in the electronic transfer system is not transferred to the receiving club but, legally, is extinguished when the receiving club registers the player and obtains a new right.\nd. the entity derecognises its intangible asset upon the receiving club registering the player in the electronic transfer system."}),"\n",(0,a.jsx)(t.p,{children:"The request asked whether the entity recognises the transfer payment received as revenue applying IFRS 15 Revenue from Contracts with Customers or, instead, recognises the gain or loss arising from the derecognition of the intangible asset in profit or loss applying IAS 38."}),"\n",(0,a.jsx)(t.h2,{id:"recognition-of-transfer-payment-received",children:"Recognition of transfer payment received"}),"\n",(0,a.jsx)(t.p,{children:"In the fact pattern described in the request, the entity recognised the registration right as an intangible asset applying IAS 38. Accordingly, the entity applies the derecognition requirements in IAS 38 on derecognition of that right."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 113 of IAS 38 states that \u2018the gain or loss arising from the derecognition of an intangible asset shall be determined as the difference between the net disposal proceeds, if any, and the carrying amount of the asset. It shall be recognised in profit or loss when the asset is derecognised \u2026 Gains shall not be classified as revenue\u2019. Applying that paragraph, the entity recognises in profit or loss, but not as revenue, the difference between the net disposal proceeds and the carrying amount of the registration right."}),"\n",(0,a.jsx)(t.h2,{id:"does-the-transfer-payment-represent-disposal-proceeds",children:"Does the transfer payment represent disposal proceeds?"}),"\n",(0,a.jsx)(t.p,{children:"The transfer payment arises from the transfer agreement, which requires the entity to release the player from the employment contract. The entity is therefore required to undertake some action for the right to be extinguished. Accordingly, the transfer payment compensates the entity for its action in disposing of the registration right and, thus, is part of the net disposal proceeds described in paragraph 113 of IAS 38."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that, in the fact pattern described in the request, the entity recognises the transfer payment received as part of the gain or loss arising from the derecognition of the registration right applying paragraph 113 of IAS 38. In the fact pattern described in the request (in which the entity recognises the registration right as an intangible asset), the entity does not recognise the transfer payment received, or any gain arising, as revenue applying IFRS 15."}),"\n",(0,a.jsx)(t.h2,{id:"statement-of-cash-flows",children:"Statement of cash flows"}),"\n",(0,a.jsx)(t.p,{children:"IAS 7 Statement of Cash Flows lists cash receipts from sales of intangibles as an example of cash flows arising from investing activities. Accordingly, in the fact pattern described in the request, the entity presents cash receipts from transfer payments as part of investing activities."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for the entity to determine the recognition of player transfer payments received. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function l(e={}){let{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,t,n){n.d(t,{R:()=>s,x:()=>o});var i=n(96540);let a={},r=i.createContext(a);function s(e){let t=i.useContext(r);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(r.Provider,{value:t},e.children)}}}]);